import {useMemo} from 'react';
import {useKitsTheme} from '../contexts/Theme';

/**
 * Known element slot keys. When a config key matches one of these
 * AND the value has `props` or `style`, it is treated as an element slot.
 *
 * To add a new slot: add the key here AND to the relevant slot interface
 * in packages/types/src/Theme/types.ts.
 */
const ELEMENT_SLOT_KEYS = new Set([
    'root', 'container', 'label', 'inputGroup', 'leftAddon', 'rightAddon',
    'helperText', 'error', 'icon', 'header', 'title', 'subTitle', 'content', 'footer',
    // Table slots
    'headerRow', 'headerCell', 'body', 'bodyRow', 'bodyCell',
    'footerCell', 'paginator', 'emptyMessage',
    'tableHeader', 'searchInput',
    'paginatorPageButton', 'paginatorActivePageButton', 'paginatorRowsPerPage',
    'sortedColumn', 'stripedRow', 'selectedRow',
    // Sidebar/Drawer slots
    'headerTitle', 'closeButton', 'mask',
    // Group slots
    'row', 'addButton', 'removeButton',
]);

export interface UseComponentDefaultsResult<T> {
    /** Props with theme defaults merged in (user props always win) */
    mergedProps: T;
    /**
     * CSS style from root slot — backwards compat for components
     * that read themeStyle instead of elementStyles.root
     */
    themeStyle: Record<string, any>;
    /**
     * Per-element style maps. Each key is a slot name, value is the
     * merged IStyleClasses (not yet resolved to CSSProperties).
     * Use `useResolvedElementStyles(elementStyles)` to resolve.
     */
    elementStyles: Record<string, Record<string, any>>;
}

/**
 * Merges theme-level component defaults with user-supplied props.
 *
 * Element slots (`root`, `label`, `container`, etc.) are direct keys
 * on the component config. Each slot accepts `{ props?, style? }`.
 *
 * The `root` slot's `props` are merged into `mergedProps` alongside
 * user props (user always wins). The `root` slot's `style` is returned
 * as both `themeStyle` (backwards compat) and `elementStyles.root`.
 *
 * Supports base-group inheritance: e.g. `useComponentDefaults('InputText', rawProps, 'Input')`
 * merges Input base config first, then InputText overrides, then user props.
 *
 * @example
 * const { mergedProps, themeStyle, elementStyles } = useComponentDefaults('InputText', rawProps, 'Input');
 * // mergedProps  → base.root.props + config.root.props + user props
 * // themeStyle   → base.root.style + config.root.style (backwards compat)
 * // elementStyles.root      → root element style
 * // elementStyles.label     → label element style
 * // elementStyles.container → container element style
 */
export default function useComponentDefaults<T extends Record<string, any>>(
    componentName: string,
    props: T,
    baseGroup?: string,
): UseComponentDefaultsResult<T> {
    const {theme} = useKitsTheme();
    const baseConfig = baseGroup ? theme.components[baseGroup] : undefined;
    const config = theme.components[componentName];

    return useMemo(() => {
        // Extract per-instance slot overrides from props (IFormElement.slots passed through)
        const instanceSlots = (props as any).slots as Record<string, { props?: any; style?: any }> | undefined;

        if (!config && !baseConfig && !instanceSlots) {
            return {mergedProps: props, themeStyle: {}, elementStyles: {}};
        }

        const base = (baseConfig || {}) as Record<string, any>;
        const comp = (config || {}) as Record<string, any>;

        // --- Props merge: base.root.props < config.root.props < instanceSlots.root.props < user props ---
        const merged = {
            ...(base.root?.props || {}),
            ...(comp.root?.props || {}),
            ...(instanceSlots?.root?.props || {}),
        } as Record<string, any>;

        for (const key of Object.keys(props)) {
            // Skip 'slots' — it is consumed here, not forwarded
            if (key === 'slots') continue;
            if (props[key] !== undefined) {
                merged[key] = props[key];
            }
        }

        // --- Element styles merge: base[slot].style < config[slot].style < instanceSlots[slot].style ---
        const allSlotKeys = new Set<string>();
        for (const key of Object.keys(base)) {
            if (ELEMENT_SLOT_KEYS.has(key)) allSlotKeys.add(key);
        }
        for (const key of Object.keys(comp)) {
            if (ELEMENT_SLOT_KEYS.has(key)) allSlotKeys.add(key);
        }
        if (instanceSlots) {
            for (const key of Object.keys(instanceSlots)) {
                if (ELEMENT_SLOT_KEYS.has(key)) allSlotKeys.add(key);
            }
        }

        const elementStyles: Record<string, Record<string, any>> = {};
        for (const slotKey of allSlotKeys) {
            elementStyles[slotKey] = {
                ...(base[slotKey]?.style || {}),
                ...(comp[slotKey]?.style || {}),
                ...(instanceSlots?.[slotKey]?.style || {}),
            };
        }

        // themeStyle = root element style (backwards compat)
        const themeStyle = elementStyles.root || {};

        return {
            mergedProps: merged as T,
            themeStyle,
            elementStyles,
        };
    }, [baseConfig, config, props]);
}
